draw((0,0)--(8,0));
draw((0,-3)--(0,3));

for (i = 1; i <= 8; ++i) {
  draw((i,-0.1)--(i,0.1));
}

draw((-0.1,3)--(0.1,3));
draw((-0.1,-3)--(0.1,-3));

